    def test_allowlist_permits_safe_commands(self):
        for cmd in ["git status", "ls -la", "pytest tests/", "python --version"]:
            allowed, reason = _is_command_allowed(cmd)
            assert allowed, f"Should have allowed: {cmd!r}, reason: {reason}"

