            await page.click_at(x, y)
            if clear:
                await page.key_press("Control+a")
                await page.key_press("Backspace")
            await page.type_text(text, delay_ms=50)
            if press_enter:
                await page.key_press("Enter")
                await browser._wait_for_page(timeout=8.0)
