            return web.json_response(
                {"error": f"not authorized to run agent '{target_agent_id}'"},
                status=403,
            )

        run = Run(
            agent_id=target_agent_id,
            session_id=req.session_id,
            mode=req.mode,
            input=req.input,
            metadata=req.metadata,
            status=RunStatus.CREATED,
